public class AppointmentService : IAppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Williams",
            "Dr. Patel"
        });
    }

    public Task<List<string>> GetTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return fixed slots regardless of doctor/date
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    public Task<List<ServerValidationError>> ValidatePatientAsync(AppointmentModel model)
    {
        var errors = new List<ServerValidationError>();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors.Add(new ServerValidationError
            {
                FieldName = nameof(model.Email),
                ErrorMessage = "Account has outstanding balance"
            });
        }

        // Reject "None" insurance with "Dr. Smith" (doesn't accept self-pay)
        if (model.InsuranceProvider == "None"
            && string.Equals(model.Doctor, "Dr. Smith", StringComparison.OrdinalIgnoreCase))
        {
            errors.Add(new ServerValidationError
            {
                FieldName = nameof(model.Doctor),
                ErrorMessage = "Selected doctor does not accept self-pay patients"
            });
        }

        // Reject "10:00 AM" as already taken (race condition simulation)
        if (model.TimeSlot == "10:00 AM")
        {
            errors.Add(new ServerValidationError
            {
                FieldName = nameof(model.TimeSlot),
                ErrorMessage = "This slot is no longer available"
            });
        }

        return Task.FromResult(errors);
    }

    public Task<bool> SubmitAppointmentAsync(AppointmentModel model)
    {
        // Stub: always succeeds if validation passed
        return Task.FromResult(true);
    }
}
