+@rendermode InteractiveServer
+@using sv_303130f45c6648979554e845ab18abc4.Models
+@using sv_303130f45c6648979554e845ab18abc4.Services
+@inject IAppointmentService AppointmentService
+
+<PageTitle>Book Appointment</PageTitle>
+
+<h1>Book a Medical Appointment</h1>
+
+@if (isSubmitted)
+{
+    <div class="alert alert-success mt-3">
+        <h4>Appointment Confirmed!</h4>
+        <p>Thank you, @model.PatientName. Your appointment with @model.Doctor on @model.AppointmentDate?.ToString("MMMM d, yyyy") at @model.TimeSlot has been scheduled.</p>
+    </div>
+    <button class="btn btn-primary mt-2" @onclick="Reset">Book Another Appointment</button>
+}
+else
+{
+    <EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="appointment">
+        <DataAnnotationsValidator />
+
+        @* ───── STEP 1 ───── *@
+        <fieldset>
+            <legend>Step 1: Patient Information</legend>
+
+            <div class="mb-3">
+                <label for="patientName" class="form-label">Patient Name</label>
+                <InputText id="patientName" class="form-control" @bind-Value="model.PatientName" />
+                <ValidationMessage For="() => model.PatientName" />
+            </div>
+
+            <div class="mb-3">
+                <label for="email" class="form-label">Email</label>
+                <InputText id="email" class="form-control" @bind-Value="model.Email" />
+                <ValidationMessage For="() => model.Email" />
+            </div>
+
+            <div class="mb-3">
+                <label for="phone" class="form-label">Phone</label>
+                <InputText id="phone" class="form-control" @bind-Value="model.Phone" />
+                <ValidationMessage For="() => model.Phone" />
+            </div>
+
+            <div class="mb-3">
+                <label for="insurance" class="form-label">Insurance Provider</label>
+                <InputSelect id="insurance" class="form-select" @bind-Value="model.InsuranceProvider">
+                    <option value="">-- Select --</option>
+                    <option value="Aetna">Aetna</option>
+                    <option value="BlueCross">BlueCross</option>
+                    <option value="Cigna">Cigna</option>
+                    <option value="UnitedHealth">UnitedHealth</option>
+                    <option value="None">None</option>
+                </InputSelect>
+                <ValidationMessage For="() => model.InsuranceProvider" />
+            </div>
+
+            @if (!showStep2)
+            {
+                <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
+                    Next: Choose Appointment
+                </button>
+            }
+        </fieldset>
+
+        @* ───── STEP 2 ───── *@
+        @if (showStep2)
+        {
+            <fieldset class="mt-4">
+                <legend>Step 2: Appointment Details</legend>
+
+                <div class="mb-3">
+                    <label for="doctor" class="form-label">Preferred Doctor</label>
+                    <InputSelect id="doctor" class="form-select" @bind-Value="model.Doctor"
+                                 @bind-Value:after="OnDoctorOrDateChanged">
+                        <option value="">-- Select --</option>
+                        @foreach (var doc in doctors)
+                        {
+                            <option value="@doc">@doc</option>
+                        }
+                    </InputSelect>
+                    <ValidationMessage For="() => model.Doctor" />
+                </div>
+
+                <div class="mb-3">
+                    <label for="date" class="form-label">Date</label>
+                    <InputDate id="date" class="form-control" @bind-Value="model.AppointmentDate"
+                               @bind-Value:after="OnDoctorOrDateChanged" />
+                    <ValidationMessage For="() => model.AppointmentDate" />
+                    @if (model.AppointmentDate.HasValue && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
+                    {
+                        <div class="text-danger">Date must be in the future.</div>
+                    }
+                </div>
+
+                <div class="mb-3">
+                    <label for="timeSlot" class="form-label">Time Slot</label>
+                    <InputSelect id="timeSlot" class="form-select" @bind-Value="model.TimeSlot"
+                                 disabled="@(!timeSlots.Any())">
+                        <option value="">-- Select --</option>
+                        @foreach (var slot in timeSlots)
+                        {
+                            <option value="@slot">@slot</option>
+                        }
+                    </InputSelect>
+                    <ValidationMessage For="() => model.TimeSlot" />
+                    @if (!timeSlots.Any() && !string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
+                    {
+                        <div class="text-muted">Loading slots…</div>
+                    }
+                </div>
+
+                <div class="mb-3">
+                    <label for="reason" class="form-label">Reason for Visit</label>
+                    <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="model.ReasonForVisit" />
+                    <ValidationMessage For="() => model.ReasonForVisit" />
+                </div>
+
+                <div class="d-flex gap-2">
+                    <button type="button" class="btn btn-outline-secondary" @onclick="BackToStep1">Back</button>
+                    <button type="button" class="btn btn-info" @onclick="CheckAvailability" disabled="@isChecking">
+                        @(isChecking ? "Checking…" : "Check Availability")
+                    </button>
+                    <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked)">
+                        Confirm Appointment
+                    </button>
+                </div>
+            </fieldset>
+        }
+    </EditForm>
+}
+
+@code {
+    private AppointmentModel model = new();
+    private EditContext editContext = default!;
+    private ValidationMessageStore serverMessageStore = default!;
+
+    private bool showStep2;
+    private bool isSubmitted;
+    private bool isChecking;
+    private bool availabilityChecked;
+
+    private List<string> doctors = new();
+    private List<string> timeSlots = new();
+
+    // Fields that belong to step 1 for partial validation
+    private static readonly string[] Step1Fields =
+    {
+        nameof(AppointmentModel.PatientName),
+        nameof(AppointmentModel.Email),
+        nameof(AppointmentModel.Phone),
+        nameof(AppointmentModel.InsuranceProvider)
+    };
+
+    protected override async Task OnInitializedAsync()
+    {
+        editContext = new EditContext(model);
+        serverMessageStore = new ValidationMessageStore(editContext);
+
+        // Clear server errors when the user edits any field
+        editContext.OnFieldChanged += (_, args) =>
+        {
+            serverMessageStore.Clear(args.FieldIdentifier);
+            availabilityChecked = false;
+        };
+
+        doctors = await AppointmentService.GetDoctorsAsync();
+    }
+
+    private void ProceedToStep2()
+    {
+        // Validate only step-1 fields
+        var isValid = true;
+        foreach (var field in Step1Fields)
+        {
+            var fi = editContext.Field(field);
+            editContext.NotifyFieldChanged(fi);
+            if (editContext.GetValidationMessages(fi).Any())
+                isValid = false;
+        }
+
+        if (isValid)
+            showStep2 = true;
+    }
+
+    private void BackToStep1()
+    {
+        showStep2 = false;
+    }
+
+    private async Task OnDoctorOrDateChanged()
+    {
+        availabilityChecked = false;
+        model.TimeSlot = string.Empty;
+        timeSlots.Clear();
+
+        if (!string.IsNullOrEmpty(model.Doctor)
+            && model.AppointmentDate.HasValue
+            && model.AppointmentDate.Value > DateOnly.FromDateTime(DateTime.Today))
+        {
+            timeSlots = await AppointmentService.GetTimeSlotsAsync(
+                model.Doctor, model.AppointmentDate.Value);
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        serverMessageStore.Clear();
+        availabilityChecked = false;
+
+        // Client-side validation for step 2 fields
+        if (!editContext.Validate())
+            return;
+
+        // Future-date guard
+        if (model.AppointmentDate.HasValue
+            && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
+            return;
+
+        isChecking = true;
+        try
+        {
+            var errors = await AppointmentService.ValidatePatientAsync(model);
+            if (errors.Count > 0)
+            {
+                foreach (var err in errors)
+                {
+                    serverMessageStore.Add(editContext.Field(err.FieldName), err.ErrorMessage);
+                }
+                editContext.NotifyValidationStateChanged();
+            }
+            else
+            {
+                availabilityChecked = true;
+            }
+        }
+        finally
+        {
+            isChecking = false;
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        if (!availabilityChecked)
+            return;
+
+        await AppointmentService.SubmitAppointmentAsync(model);
+        isSubmitted = true;
+    }
+
+    private void Reset()
+    {
+        model = new AppointmentModel();
+        editContext = new EditContext(model);
+        serverMessageStore = new ValidationMessageStore(editContext);
+        editContext.OnFieldChanged += (_, args) =>
+        {
+            serverMessageStore.Clear(args.FieldIdentifier);
+            availabilityChecked = false;
+        };
+
+        showStep2 = false;
+        isSubmitted = false;
+        availabilityChecked = false;
+        timeSlots.Clear();
+    }
+}
+

